Return JSON only in this schema:
{
  "action": "continue" | "done",
  "reason": "short rationale",
  "skip_lemma": false,
  "skip_critique": false,
  "skip_patch": false,
  "skip_merge": false,
  "focus": {
    "explorer_a": "...",
    "explorer_b": "...",
    "explorer_c": "..."
  }
}
